const ALLOWED = [
  'order_index','scheduled_date','name','asset_url','thumbnail_url',
  'caption','caption_alt','caption_alt_platform','post_url','cta','tweaks','status','linear_issue_id',
  'kasper_approved_at','posted_at','platform','platforms','color',
  'video_status','graphic_status','caption_status',
  'graphic_linear_issue_id',
  'video_tweaks','graphic_tweaks','caption_tweaks',
    'client_video_approved_at','client_graphic_approved_at','client_caption_approved_at',
  'kasper_seen','kasper_approved_after_tweaks'
];
const body = ($input.first() && $input.first().json && $input.first().json.body) || {};
const client = String(body.client || '').trim();
if (!client) throw new Error('client required');
const post = body.post || {};
let id = String(post.id || '').trim();
if (!id) {
  id = 'p_' + Date.now().toString(36) + '_' + Math.random().toString(36).slice(2,8);
}
const row = { id, updated_at: new Date().toISOString() };
for (const k of ALLOWED) {
  if (Object.prototype.hasOwnProperty.call(post, k)) {
    const v = post[k];
    row[k] = v == null ? '' : String(v);
  }
}
const baseAt = String(body.comments_base_at || '');
return [{ json: { ...row, _sheetName: 'Calendar_' + client, _client: client, _baseAt: baseAt } }];

const incoming = $('Build Row From Patch').first().json;
const existingArr = $('Read Existing Row').all();
const existing = (existingArr[0] && existingArr[0].json) || {};
// Read Link Twins output: rows in this tab whose linear_issue_id equals the
// incoming one (its lookup uses a __no_link__ sentinel when the incoming link
// is blank, so a blank link never matches anything).
const twinItems = $input.all();

// Read-failure guard (added 2026-06-14): 'Read Existing Row' runs with
// onError: continueRegularOutput, so a Google Sheets API failure is forwarded
// as an item whose .json.error (string) / .error (object) is set instead of a
// real row. That is indistinguishable from "row not found" (existsAlready=false),
// which makes the phantom-row guard THROW a status-only patch (a lost save) and
// bypasses the link-clobber/conflict guards on content patches. Detect the
// failed read and return a clean, retryable {ok:false} via the existing no-write
// path (Is Conflict -> Respond JSON) so the FE shows "try again" and keeps the
// user's text. (Sheets outage 2026-06-14, exec 68798: read hung 185s then
// returned {json:{error:'Service unavailable...'}}.)
const _readItem = existingArr[0] || {};
if (_readItem.error || (_readItem.json && _readItem.json.error)) {
  return [{ json: { _conflict: true, ok: false, id: incoming.id,
    error: 'Not saved \u2014 the calendar store was briefly unavailable. Your text is kept; please try again in a moment.' } }];
}

// Phantom-row guard: if no existing row AND the incoming payload has no
// substantive content fields, abort. This blocks the misrouted-skeleton
// bug pattern where the FE accidentally calls upsert with a stale id and
// no real fields, causing Sheets appendOrUpdate to create an empty ghost
// row in the wrong tab. Real creates always include at least one of:
// caption / caption_alt / name / asset_url / thumbnail_url /
// linear_issue_id / scheduled_date / cta / color / platforms /
// graphic_linear_issue_id.
const existsAlready = !!(existing && existing.id);
const CONTENT_FIELDS = ['caption','caption_alt','name','asset_url','thumbnail_url','linear_issue_id','scheduled_date','cta','color','platforms','graphic_linear_issue_id'];
const hasContent = CONTENT_FIELDS.some(k => String(incoming[k] == null ? '' : incoming[k]).trim() !== '');
if (!existsAlready && !hasContent) {
  throw new Error('phantom-row guard: refusing to create a row in ' + (incoming._sheetName || '?') + ' with id ' + incoming.id + ' because the row does not exist and the payload contains no substantive content fields. This is the misrouted-skeleton pattern.');
}

const baseAt = String(incoming._baseAt || '');
const RETAIN_MS = 30*24*60*60*1000;
const nowMs = Date.now();
function parse(s){ try { const a = JSON.parse(s == null ? '[]' : (String(s) || '[]')); return Array.isArray(a) ? a.filter(c => c && c.id) : []; } catch (e) { return []; } }
function stamp(c){ return String((c && (c.updated_at || c.created_at)) || ''); }
function mergeCell(existingStr, incomingStr){
  const ex = parse(existingStr), inc = parse(incomingStr);
  const incIds = new Set(inc.map(c => c.id));
  const exById = new Map(ex.map(c => [c.id, c]));
  const out = [];
  for (const c of inc){ const e = exById.get(c.id); out.push(e && stamp(e) > stamp(c) ? e : c); }
  for (const e of ex){
    if (incIds.has(e.id)) continue;
    if (e.deleted) { out.push(e); continue; }
    const es = stamp(e);
    if (!baseAt) { out.push(e); continue; }
    if (es && es > baseAt) out.push(e);
  }
  const cutoff = nowMs - RETAIN_MS;
  const kept = out.filter(function(c){ if (!c.deleted) return true; const t = Date.parse(c.updated_at || c.created_at || ''); return !(isFinite(t) && t < cutoff); });
  return kept.length ? JSON.stringify(kept) : '';
}
const row = Object.assign({}, incoming);
for (const col of ['video_tweaks','graphic_tweaks','caption_tweaks']){
  if (Object.prototype.hasOwnProperty.call(incoming, col)) row[col] = mergeCell(existing[col], incoming[col]);
}
if (Object.prototype.hasOwnProperty.call(incoming, 'video_tweaks')) row.tweaks = row.video_tweaks;

// Explicit link clear: the literal value '__CLEAR_LINK__' removes a stored
// link, bypassing the carry-forward guard below (a plain '' can never clear,
// by design — see link-clobber guard).
const CLEAR = '__CLEAR_LINK__';
const cleared = {};
for (const linkCol of ['graphic_linear_issue_id','linear_issue_id']){
  if (Object.prototype.hasOwnProperty.call(incoming, linkCol)
      && String(incoming[linkCol] == null ? '' : incoming[linkCol]).trim() === CLEAR) {
    row[linkCol] = '';
    cleared[linkCol] = true;
  }
}

// Link-clobber guard: a full-card save from a stale or secondary client tab
// can carry an empty graphic_linear_issue_id / linear_issue_id. Without this,
// appendOrUpdate would overwrite a real saved Linear link with ''. Carry the
// stored value forward whenever the incoming link is blank but one exists.
for (const linkCol of ['graphic_linear_issue_id','linear_issue_id']){
  if (cleared[linkCol]) continue;
  if (Object.prototype.hasOwnProperty.call(incoming, linkCol)
      && String(incoming[linkCol] == null ? '' : incoming[linkCol]).trim() === ''
      && String(existing[linkCol] == null ? '' : existing[linkCol]).trim() !== '') {
    row[linkCol] = existing[linkCol];
  }
}

// Duplicate-link guard: linear_issue_id must stay unique across live rows in
// a tab — the FE collapses cards sharing a link to a single visible card,
// which is how cards "disappear" and swap titles/dates (Dr. Sonia, 2026-06-11,
// VID-12598 ended up on two rows). If another non-archived row already owns
// the incoming link: a CREATE proceeds unlinked, an UPDATE keeps the link it
// already had.
const incomingLink = (!cleared.linear_issue_id && Object.prototype.hasOwnProperty.call(incoming, 'linear_issue_id'))
  ? String(incoming.linear_issue_id == null ? '' : incoming.linear_issue_id).trim() : '';
if (incomingLink) {
  const twin = twinItems.map(t => (t && t.json) || {}).find(t => t.id
    && String(t.id) !== String(incoming.id)
    && String(t.status || '').toLowerCase() !== 'archived'
    && String(t.linear_issue_id || '').trim() === incomingLink);
  if (twin) {
    if (!existsAlready) {
      row.linear_issue_id = '';
    } else if (String(existing.linear_issue_id == null ? '' : existing.linear_issue_id).trim() !== incomingLink) {
      row.linear_issue_id = existing.linear_issue_id == null ? '' : existing.linear_issue_id;
    }
  }
}

// Conflict guard: comments_base_at is the sheet updated_at this browser last
// saw for the card (advanced on every fetch and save echo). If the stored row
// is newer than that base, another browser saved in between — and if this
// save would ALSO change a scalar field, last-writer-wins would silently
// revert the other person's edit (the date/title flip-flop two concurrent
// SMMs hit on Dr. Sonia's calendar). Block it; the FE shows the error on the
// card's save chip. Comment-only saves pass through (the 3-way merge above
// already handles concurrent comments), as do saves without a base (bulk
// import, settings row, server-side callers). Compared against the EFFECTIVE
// row (after carry-forward/dup guards) so a blank carried-forward link never
// counts as a change.
if (existsAlready && baseAt) {
  const storedAt = String(existing.updated_at || '');
  if (storedAt && storedAt > baseAt) {
    const SCALAR_FIELDS = ['scheduled_date','name','caption','caption_alt','caption_alt_platform','asset_url','thumbnail_url','post_url','cta','status','video_status','graphic_status','caption_status','linear_issue_id','graphic_linear_issue_id','platform','platforms','color','kasper_approved_at','posted_at'];
    const changed = SCALAR_FIELDS.filter(k => Object.prototype.hasOwnProperty.call(incoming, k)
      && String(row[k] == null ? '' : row[k]) !== String(existing[k] == null ? '' : existing[k]));
    if (changed.length) {
      return [{ json: { _conflict: true, ok: false, conflict: true, id: incoming.id,
        error: 'Not saved: someone else updated this card (' + changed.join(', ') + ') after your screen last loaded it. Refresh the calendar to see their version, then re-apply your change.' } }];
    }
  }
}

row._conflict = false;
return [{ json: row }];

const j = $input.item.json;
const out = {};
for (const k of Object.keys(j)) {
  if (k.charAt(0) === '_') continue;
  out[k] = j[k];
}
return { json: out };

const j = ($input.first() && $input.first().json) || {};
const post = j || {};
return [{ json: { ok: true, post } }];

const client = $('Build Row From Patch').first().json._client;
const row = $('Upsert Calendar Row').first().json || {};
return [{ json: Object.assign({ client }, row) }];
